async function fetchData() {
  try {
    const response = await fetch('https://api.example.com/data');
    if (!response.ok) {
      throw new Error('Network response was not ok');
    }
    const data = await response.json();
    console.log(data); // The actual data
  } catch (error) {
    console.error('Fetch error:', error);
  }
}

async function fetchWithTryCatch() {
  try {
    const response = await fetch('https://api.example.com/data');
    const data = await response.json();
    console.log(data);
  } catch (error) {
    console.error('Error caught inside async function:', error);
  }
}

import * as WebSocket from 'ws';

const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', (ws) => {
  console.log('User connected');

  ws.on('message', (message: string) => {
    console.log(`Received: ${message}`);
    // Broadcast the received message to all clients
    wss.clients.forEach(client => {
      if (client !== ws && client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    });
  });

  ws.on('close', () => {
    console.log('User disconnected');
  });
});

console.log('WebSocket server is running on ws://localhost:8080');

function handleError(e: unknown) {
  if (e instanceof Error) {
    // TypeScript now knows e is an Error object
    console.error('Error message:', e.message);
  } else if (typeof e === 'string') {
    // We narrowed e to string
    console.error('String error:', e);
  } else {
    console.error('Unknown error:', e);
  }
}

try {
  throw new Error('Something went wrong!');
} catch (err) {
  handleError(err);
}

function isError(e: unknown): e is Error {
  return e instanceof Error;
}

function handleError(e: unknown) {
  if (isError(e)) {
    console.error('Caught an error:', e.message);
  } else {
    console.error('Non-error thrown:', e);
  }
}

def divide_numbers(a, b):
    try:
        result = a / b
    except ZeroDivisionError:
        print("Error: Cannot divide by zero.")
    except TypeError:
        print("Error: Inputs must be numbers.")
    else:
        print(f"Result is {result}")

# Example usage

# Valid input
divide_numbers(10, 2)

# Division by zero
divide_numbers(10, 0)

# Wrong input type
divide_numbers(10, 'five')

